import { createAuthPlugin } from "@better-auth-ui/core"
import {
  organizationPlugin as coreOrganizationPlugin,
  type OrganizationLocalization,
  type OrganizationPluginOptions
} from "@better-auth-ui/core/plugins"
import { BriefcaseBusiness } from "lucide-solid"
import type { Component } from "solid-js"
import { OrganizationsSettings } from "@/components/auth/organization/organizations-settings"

export type SolidSettingsTab = {
  view: string
  tabLabel: Component
  component: Component
}

export const organizationPlugin = createAuthPlugin(
  coreOrganizationPlugin.id,
  (options: OrganizationPluginOptions = {}) => {
    const core = coreOrganizationPlugin(options)

    return {
      ...core,
      localization: core.localization as OrganizationLocalization,
      settingsTabs: [
        {
          view: "organizations",
          tabLabel: () => (
            <span class="inline-flex items-center gap-1">
              <BriefcaseBusiness class="size-4 text-muted-foreground" />
              {core.localization.organizations}
            </span>
          ),
          component: OrganizationsSettings
        }
      ] satisfies SolidSettingsTab[]
    }
  }
)

import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import { useListOrganizations } from "@better-auth-ui/solid"
import { PlusCircle } from "lucide-solid"
import { createSignal, For, Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { CreateOrganizationDialog } from "./create-organization-dialog"
import { OrganizationRow } from "./organization-row"

export type OrganizationsProps = {
  authClient: OrganizationAuthClient
}

export function Organizations(props: OrganizationsProps) {
  const organizations = useListOrganizations(props.authClient)
  const [createOpen, setCreateOpen] = createSignal(false)

  return (
    <div class="flex flex-col gap-4">
      <div class="flex items-center justify-between gap-3">
        <div>
          <h3 class="font-medium">Organizations</h3>
          <p class="text-sm text-muted-foreground">
            Create and manage organizations for shared access.
          </p>
        </div>
        <Button onClick={() => setCreateOpen(true)} type="button">
          <PlusCircle class="size-4" />
          Create organization
        </Button>
      </div>

      <Show
        when={!organizations.isPending}
        fallback={
          <p class="text-sm text-muted-foreground">Loading organizations…</p>
        }
      >
        <div class="flex flex-col gap-2">
          <For
            each={organizations.data ?? []}
            fallback={
              <button
                class="rounded-md border border-dashed p-4 text-left text-sm text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground"
                onClick={() => setCreateOpen(true)}
                type="button"
              >
                No organizations yet. Create one to enable organization routes.
              </button>
            }
          >
            {(organization) => (
              <OrganizationRow
                authClient={props.authClient}
                organization={organization}
              />
            )}
          </For>
        </div>
      </Show>

      <CreateOrganizationDialog
        open={createOpen()}
        onOpenChange={setCreateOpen}
      />
    </div>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import { useAuth, useCreateOrganization } from "@better-auth-ui/solid"
import { BriefcaseBusiness, LoaderCircle } from "lucide-solid"
import { createEffect, createSignal } from "solid-js"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { SlugField, sanitizeSlug } from "./slug-field"

export type CreateOrganizationDialogProps = {
  open: boolean
  onOpenChange: (open: boolean) => void
}

const organizationFallbackLocalization = {
  createOrganization: "Create organization",
  name: "Name",
  namePlaceholder: "Enter the organization name",
  organizationsDescription:
    "Create an organization to collaborate with others and manage shared access."
} satisfies Pick<
  OrganizationLocalization,
  "createOrganization" | "name" | "namePlaceholder" | "organizationsDescription"
>

export function CreateOrganizationDialog(props: CreateOrganizationDialogProps) {
  const auth = useAuth()
  const [name, setName] = createSignal("")
  const [slug, setSlug] = createSignal("")
  const createOrganization = useCreateOrganization(
    auth.authClient as OrganizationAuthClient,
    {
      onSuccess: () => props.onOpenChange(false)
    }
  )
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { localization?: OrganizationLocalization }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? organizationFallbackLocalization

  createEffect(() => {
    if (!props.open) {
      setName("")
      setSlug("")
      return
    }

    setSlug(sanitizeSlug(name()))
  })

  const handleSubmit = (event: SubmitEvent) => {
    event.preventDefault()

    createOrganization.mutate({
      name: name(),
      slug: slug()
    })
  }

  return (
    <Dialog open={props.open} onOpenChange={props.onOpenChange}>
      <DialogContent>
        <form class="flex flex-col gap-6" onSubmit={handleSubmit}>
          <DialogHeader>
            <div class="flex size-10 items-center justify-center rounded-md bg-muted">
              <BriefcaseBusiness class="size-4.5" />
            </div>
            <DialogTitle>{localization().createOrganization}</DialogTitle>
            <DialogDescription>
              {localization().organizationsDescription}
            </DialogDescription>
          </DialogHeader>

          <div class="grid gap-2">
            <Label for="create-organization-name">{localization().name}</Label>
            <Input
              autofocus
              disabled={createOrganization.isPending}
              id="create-organization-name"
              name="name"
              onInput={(event) => setName(event.currentTarget.value)}
              placeholder={localization().namePlaceholder}
              required
              value={name()}
            />
          </div>

          <SlugField
            disabled={createOrganization.isPending}
            id="create-organization-slug"
            onChange={setSlug}
            value={slug()}
          />

          <DialogFooter>
            <DialogClose
              as={Button}
              disabled={createOrganization.isPending}
              type="button"
              variant="outline"
            >
              {auth.localization.settings.cancel}
            </DialogClose>
            <Button disabled={createOrganization.isPending} type="submit">
              {createOrganization.isPending ? (
                <>
                  <LoaderCircle class="size-4 animate-spin" />
                  {localization().createOrganization}
                </>
              ) : (
                localization().createOrganization
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import { useAuth, useCheckOrganizationSlug } from "@better-auth-ui/solid"
import { Check, LoaderCircle, X } from "lucide-solid"
import { createEffect } from "solid-js"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"

export type SlugFieldProps = {
  value: string
  onChange: (value: string) => void
  currentSlug?: string
  disabled?: boolean
  id?: string
}

export function sanitizeSlug(value: string) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-")
}

const organizationFallbackLocalization = {
  slug: "Slug",
  slugPlaceholder: "organization-slug"
} satisfies Pick<OrganizationLocalization, "slug" | "slugPlaceholder">

export function SlugField(props: SlugFieldProps) {
  const auth = useAuth()
  const checkOrganizationSlug = useCheckOrganizationSlug(
    auth.authClient as OrganizationAuthClient
  )
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | {
          checkSlug?: boolean
          localization?: Pick<
            OrganizationLocalization,
            "slug" | "slugPlaceholder"
          >
        }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? organizationFallbackLocalization
  const checkSlug = () => organizationPluginConfig()?.checkSlug ?? true
  const shouldCheckSlug = () =>
    checkSlug() &&
    !!props.value.trim() &&
    props.value.trim() !== props.currentSlug

  createEffect(() => {
    if (!shouldCheckSlug()) {
      checkOrganizationSlug.reset()
      return
    }

    checkOrganizationSlug.mutate({ slug: props.value.trim() })
  })

  return (
    <div class="grid gap-2">
      <Label for={props.id ?? "slug"}>{localization().slug}</Label>
      <div class="relative">
        <Input
          id={props.id ?? "slug"}
          name="slug"
          value={props.value}
          onInput={(event) =>
            props.onChange(sanitizeSlug(event.currentTarget.value))
          }
          placeholder={localization().slugPlaceholder}
          required
          disabled={props.disabled}
          class="pr-10"
        />
        {shouldCheckSlug() ? (
          <span class="absolute inset-y-0 right-3 inline-flex items-center">
            {checkOrganizationSlug.data?.status ? (
              <Check class="size-4 text-foreground" />
            ) : checkOrganizationSlug.error ? (
              <X class="size-4 text-destructive" />
            ) : (
              <LoaderCircle class="size-4 animate-spin text-muted-foreground" />
            )}
          </span>
        ) : null}
      </div>
    </div>
  )
}

import { useAuth } from "@better-auth-ui/solid"
import { For } from "solid-js"
import type { OrganizationCardsPlugin } from "@/components/auth/settings/shared/types"
import { OrganizationProfile } from "./organization-profile"

export type OrganizationSettingsProps = {
  class?: string
}

export function OrganizationSettings(props: OrganizationSettingsProps) {
  const auth = useAuth()
  const organizationCards = () =>
    (auth.plugins as OrganizationCardsPlugin[]).flatMap(
      (plugin) => plugin.organizationCards ?? []
    )

  return (
    <div class={props.class ?? "grid gap-4 md:gap-6"}>
      <OrganizationProfile />
      <For each={organizationCards()}>
        {(OrganizationCard) => <OrganizationCard />}
      </For>
    </div>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import {
  useActiveOrganization,
  useAuth,
  useUpdateOrganization
} from "@better-auth-ui/solid"
import { createEffect, createSignal, Show } from "solid-js"
import { toast } from "solid-sonner"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Skeleton } from "@/components/ui/skeleton"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { authClient } from "@/lib/auth-client"
import { ChangeOrganizationLogo } from "./change-organization-logo"
import { SlugField } from "./slug-field"

export type OrganizationProfileProps = {
  class?: string
}

const fallbackLocalization = {
  organizationProfile: "Organization profile",
  organizationsDescription:
    "Create an organization to collaborate with others and manage shared access.",
  name: "Name",
  namePlaceholder: "Enter the organization name",
  organizationUpdatedSuccess: "Organization updated successfully"
} satisfies Pick<
  OrganizationLocalization,
  | "organizationProfile"
  | "organizationsDescription"
  | "name"
  | "namePlaceholder"
  | "organizationUpdatedSuccess"
>

export function OrganizationProfile(props: OrganizationProfileProps) {
  const auth = useAuth()
  const activeOrganization = useActiveOrganization(
    authClient as OrganizationAuthClient
  )
  const updateOrganization = useUpdateOrganization(
    authClient as OrganizationAuthClient,
    {
      onSuccess: () => toast.success(localization().organizationUpdatedSuccess)
    }
  )
  const [name, setName] = createSignal("")
  const [slug, setSlug] = createSignal("")
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { localization?: OrganizationLocalization }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization

  createEffect(() => {
    const organization = activeOrganization.data

    if (!organization) return

    setName(organization.name)
    setSlug(organization.slug)
  })

  const handleSubmit = (event: SubmitEvent) => {
    event.preventDefault()

    updateOrganization.mutate({ data: { name: name(), slug: slug() } })
  }

  return (
    <Card class={props.class}>
      <form onSubmit={handleSubmit}>
        <CardHeader>
          <CardTitle>{localization().organizationProfile}</CardTitle>
          <CardDescription>
            {localization().organizationsDescription}
          </CardDescription>
        </CardHeader>
        <CardContent class="grid gap-6">
          <ChangeOrganizationLogo />

          <Show
            when={activeOrganization.data}
            fallback={
              <div class="grid gap-4">
                <Skeleton class="h-10 rounded-md" />
                <Skeleton class="h-10 rounded-md" />
              </div>
            }
          >
            {(organization) => (
              <>
                <div class="grid gap-2">
                  <Label for="organization-profile-name">
                    {localization().name}
                  </Label>
                  <Input
                    disabled={updateOrganization.isPending}
                    id="organization-profile-name"
                    name="name"
                    onInput={(event) => setName(event.currentTarget.value)}
                    placeholder={localization().namePlaceholder}
                    required
                    value={name()}
                  />
                </div>

                <SlugField
                  currentSlug={organization().slug}
                  disabled={updateOrganization.isPending}
                  id="organization-profile-slug"
                  onChange={setSlug}
                  value={slug()}
                />
              </>
            )}
          </Show>
        </CardContent>
        <CardFooter class="justify-end">
          <Button
            disabled={!activeOrganization.data || updateOrganization.isPending}
            type="submit"
          >
            {auth.localization.settings.saveChanges}
          </Button>
        </CardFooter>
      </form>
    </Card>
  )
}

import type { Organization } from "better-auth/client"
import { BriefcaseBusiness } from "lucide-solid"
import type { JSX } from "solid-js"
import { Show } from "solid-js"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Skeleton } from "@/components/ui/skeleton"
import { cn } from "@/lib/utils"

export type OrganizationLogoSize = "sm" | "md" | "lg"

export type OrganizationLogoProps = {
  class?: string
  fallback?: JSX.Element
  isPending?: boolean
  organization?: Partial<Organization>
  size?: OrganizationLogoSize
}

const sizeClass: Record<OrganizationLogoSize, string> = {
  sm: "size-8",
  md: "size-10",
  lg: "size-12"
}

function getInitials(name?: string | null) {
  const normalized = name?.trim()

  if (!normalized) return null

  return normalized.slice(0, 2).toUpperCase()
}

export function OrganizationLogo(props: OrganizationLogoProps) {
  const size = () => props.size ?? "md"
  const logo = () => props.organization?.logo?.trim()
  const label = () => props.organization?.name ?? "Organization"
  const fallback = () =>
    props.fallback ??
    getInitials(props.organization?.name) ?? (
      <BriefcaseBusiness class="size-4" />
    )

  return (
    <Show
      when={!props.isPending || props.organization}
      fallback={
        <Skeleton class={cn("rounded-md", sizeClass[size()], props.class)} />
      }
    >
      <Avatar
        class={cn(
          "rounded-md bg-muted text-muted-foreground",
          sizeClass[size()],
          props.class
        )}
      >
        <Show when={logo()}>
          {(src) => <AvatarImage alt={label()} src={src()} />}
        </Show>
        <AvatarFallback class="rounded-md bg-muted text-muted-foreground">
          {fallback()}
        </AvatarFallback>
      </Avatar>
    </Show>
  )
}

import { fileToBase64 } from "@better-auth-ui/core"
import type { OrganizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import {
  useActiveOrganization,
  useAuth,
  useUpdateOrganization
} from "@better-auth-ui/solid"
import { Trash2, Upload } from "lucide-solid"
import { createSignal, Show } from "solid-js"
import { toast } from "solid-sonner"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger
} from "@/components/ui/dropdown-menu"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { authClient } from "@/lib/auth-client"
import { OrganizationLogo } from "./organization-logo"

export type ChangeOrganizationLogoProps = {
  class?: string
}

type LogoConfig = {
  enabled?: boolean
  resize?: (file: File, size?: number, extension?: string) => Promise<File>
  size?: number
  extension?: string
  upload?: (file: File) => Promise<string>
  delete?: (url: string) => Promise<void>
}

const fallbackLocalization = {
  logo: "Logo",
  changeLogo: "Change logo",
  uploadLogo: "Upload logo",
  deleteLogo: "Delete logo",
  logoChangedSuccess: "Logo updated successfully",
  logoDeletedSuccess: "Logo removed successfully"
} satisfies Pick<
  OrganizationLocalization,
  | "logo"
  | "changeLogo"
  | "uploadLogo"
  | "deleteLogo"
  | "logoChangedSuccess"
  | "logoDeletedSuccess"
>

export function ChangeOrganizationLogo(props: ChangeOrganizationLogoProps) {
  const auth = useAuth()
  const activeOrganization = useActiveOrganization(
    authClient as OrganizationAuthClient
  )
  const updateOrganization = useUpdateOrganization(
    authClient as OrganizationAuthClient
  )
  const [isUploadingLogo, setIsUploadingLogo] = createSignal(false)
  const [isDeletingLogo, setIsDeletingLogo] = createSignal(false)
  let logoFileInput: HTMLInputElement | undefined
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { logo?: LogoConfig; localization?: OrganizationLocalization }
      | undefined
  const logo = () => organizationPluginConfig()?.logo ?? { enabled: true }
  const localization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization
  const isPending = () =>
    activeOrganization.isPending ||
    updateOrganization.isPending ||
    isUploadingLogo() ||
    isDeletingLogo()

  const handleLogoFileChange = async (event: Event) => {
    const input = event.currentTarget as HTMLInputElement
    const file = input.files?.[0]

    if (!file) return

    input.value = ""
    setIsUploadingLogo(true)

    try {
      const resized =
        (await logo().resize?.(file, logo().size, logo().extension)) || file
      const image =
        (await logo().upload?.(resized)) || (await fileToBase64(resized))

      updateOrganization.mutate(
        { data: { logo: image } },
        {
          onSuccess: () => toast.success(localization().logoChangedSuccess)
        }
      )
    } catch (error) {
      if (error instanceof Error) toast.error(error.message)
    } finally {
      setIsUploadingLogo(false)
    }
  }

  const deleteLogo = () => {
    const currentLogo = activeOrganization.data?.logo?.trim()

    updateOrganization.mutate(
      { data: { logo: "" } },
      {
        onSuccess: async () => {
          if (currentLogo) {
            setIsDeletingLogo(true)
            try {
              await logo().delete?.(currentLogo)
            } finally {
              setIsDeletingLogo(false)
            }
          }

          toast.success(localization().logoDeletedSuccess)
        }
      }
    )
  }

  return (
    <Show when={logo().enabled !== false}>
      <div class={props.class ?? "grid gap-2"}>
        <Label>{localization().logo}</Label>
        <input
          accept="image/*"
          class="hidden"
          onChange={handleLogoFileChange}
          ref={logoFileInput}
          type="file"
        />
        <div class="flex items-center gap-4">
          <Button
            class="h-auto w-auto rounded-md p-0"
            disabled={isPending()}
            onClick={() => logoFileInput?.click()}
            type="button"
            variant="ghost"
          >
            <OrganizationLogo
              isPending={activeOrganization.isPending}
              organization={activeOrganization.data ?? undefined}
              size="lg"
            />
          </Button>

          <DropdownMenu>
            <DropdownMenuTrigger
              as={Button}
              class=""
              disabled={!activeOrganization.data || isPending()}
              size="sm"
              variant="secondary"
            >
              {localization().changeLogo}
            </DropdownMenuTrigger>
            <DropdownMenuContent class="min-w-fit">
              <DropdownMenuItem onSelect={() => logoFileInput?.click()}>
                <Upload class="text-muted-foreground" />
                {localization().uploadLogo}
              </DropdownMenuItem>
              <DropdownMenuItem
                disabled={!activeOrganization.data?.logo}
                onSelect={deleteLogo}
                variant="destructive"
              >
                <Trash2 />
                {localization().deleteLogo}
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>
    </Show>
  )
}

import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import { useAuth, useSetActiveOrganization } from "@better-auth-ui/solid"
import { useNavigate } from "@tanstack/solid-router"
import type { Organization } from "better-auth/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { organizationPlugin } from "@/lib/auth/organization-plugin"

export type OrganizationRowProps = {
  authClient: OrganizationAuthClient
  organization: Organization
}

export function OrganizationRow(props: OrganizationRowProps) {
  const auth = useAuth()
  const navigate = useNavigate()
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { slug?: string | null }
      | undefined
  const isSlugMode = () => {
    const plugin = organizationPluginConfig()

    if (!plugin) return false

    return plugin.slug !== undefined
  }
  const navigateToOrganization = () => {
    navigate({
      to: "/organization/$slug/$path",
      params: {
        slug: props.organization.slug,
        path: "settings"
      }
    })
  }
  const setActiveOrganization = useSetActiveOrganization(props.authClient, {
    onSuccess: navigateToOrganization
  })

  const openOrganization = () => {
    if (isSlugMode()) {
      navigateToOrganization()
      return
    }

    setActiveOrganization.mutate({
      organizationId: props.organization.id
    })
  }

  return (
    <Card size="sm">
      <CardContent class="flex items-center justify-between gap-4 py-3">
        <div class="min-w-0">
          <p class="truncate text-sm font-medium">{props.organization.name}</p>
          <p class="truncate text-xs text-muted-foreground">
            /organization/{props.organization.slug}/settings
          </p>
        </div>
        <Button
          size="sm"
          variant="outline"
          disabled={setActiveOrganization.isPending}
          onClick={openOrganization}
        >
          Open
        </Button>
      </CardContent>
    </Card>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins"
import type { OrganizationAuthClient } from "@better-auth-ui/solid"
import {
  useActiveOrganization,
  useAuth,
  useListOrganizations,
  useSetActiveOrganization
} from "@better-auth-ui/solid"
import { useNavigate } from "@tanstack/solid-router"
import type { Organization } from "better-auth/client"
import {
  BriefcaseBusiness,
  ChevronsUpDown,
  PlusCircle,
  Settings,
  User
} from "lucide-solid"
import type { JSX } from "solid-js"
import {
  createMemo,
  createSignal,
  For,
  mergeProps,
  onMount,
  Show
} from "solid-js"
import { UserView } from "@/components/auth/user/user-view"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger
} from "@/components/ui/dropdown-menu"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { authClient } from "@/lib/auth-client"
import { CreateOrganizationDialog } from "./create-organization-dialog"

export type OrganizationSwitcherProps = {
  class?: string
  trigger?: JSX.Element
  hidePersonal?: boolean
  hideSettings?: boolean
  hideSlug?: boolean
  hideCreate?: boolean
  setActive?: (organization: Organization | null) => void
}

function OrganizationLabel(props: {
  organization: Organization
  hideSlug: boolean
}) {
  return (
    <span class="grid min-w-0 flex-1 text-left">
      <span class="truncate">{props.organization.name}</span>
      <Show when={!props.hideSlug}>
        <span class="truncate text-xs text-muted-foreground">
          /{props.organization.slug}
        </span>
      </Show>
    </span>
  )
}

function OrganizationSwitcherTrigger(rawProps: OrganizationSwitcherProps = {}) {
  const props = mergeProps({ hideSlug: true }, rawProps)

  return (
    <Show
      when={props.trigger}
      fallback={
        <Button class={props.class} disabled variant="ghost">
          <BriefcaseBusiness class="size-4 text-muted-foreground" />
          <span class="hidden max-w-36 truncate sm:inline">Organization</span>
          <ChevronsUpDown class="size-4 text-muted-foreground" />
        </Button>
      }
    >
      {props.trigger}
    </Show>
  )
}

function MountedOrganizationSwitcher(rawProps: OrganizationSwitcherProps = {}) {
  const props = mergeProps({ hideSlug: true }, rawProps)
  const auth = useAuth()
  const client = authClient as OrganizationAuthClient
  const navigate = useNavigate()
  const activeOrganization = useActiveOrganization(client)
  const organizations = useListOrganizations(client)
  const setActiveOrganization = useSetActiveOrganization(client)
  const [createOpen, setCreateOpen] = createSignal(false)
  const [isOpen, setIsOpen] = createSignal(false)
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | {
          slug?: string | null
          localization?: Pick<
            OrganizationLocalization,
            "createOrganization" | "organizations" | "manage"
          >
        }
      | undefined
  const isSlugMode = () => {
    const plugin = organizationPluginConfig()

    if (!plugin) return false

    return plugin.slug !== undefined
  }
  const selectableOrganizations = () =>
    ((organizations.data ?? []) as Organization[]).filter(
      (organization) => organization.id !== activeOrganization.data?.id
    )
  const organizationLocalization = () =>
    organizationPluginConfig()?.localization ?? {
      createOrganization: "Create organization",
      organizations: "Organizations",
      manage: "Manage"
    }

  const navigateToOrganization = (organization: Organization) => {
    navigate({
      to: "/organization/$slug/$path",
      params: { slug: organization.slug, path: "settings" }
    })
  }

  const navigateToPersonal = () => {
    navigate({
      to: "/settings/$path",
      params: { path: "account" }
    })
  }

  const handleSetActive = (organization: Organization | null) => {
    setIsOpen(false)

    if (organization) props.setActive?.(organization)
    if (!organization) props.setActive?.(null)
    if (props.setActive) return

    if (isSlugMode()) {
      if (organization) {
        navigateToOrganization(organization)
        return
      }

      navigateToPersonal()
      return
    }

    setActiveOrganization.mutate(
      { organizationId: organization?.id ?? null },
      {
        onSuccess: () => {
          if (organization) {
            navigateToOrganization(organization)
            return
          }

          navigateToPersonal()
        }
      }
    )
  }

  return (
    <>
      <DropdownMenu open={isOpen()} onOpenChange={setIsOpen}>
        <Show
          when={props.trigger}
          fallback={
            <DropdownMenuTrigger
              as={Button}
              variant="ghost"
              class={props.class}
              disabled={organizations.isPending}
            >
              <BriefcaseBusiness class="size-4 text-muted-foreground" />
              <span class="hidden max-w-36 truncate sm:inline">
                {activeOrganization.data?.name ?? "Organization"}
              </span>
              <ChevronsUpDown class="size-4 text-muted-foreground" />
            </DropdownMenuTrigger>
          }
        >
          <DropdownMenuTrigger as="span" class={props.class}>
            {props.trigger}
          </DropdownMenuTrigger>
        </Show>
        <DropdownMenuContent class="min-w-64">
          <DropdownMenuLabel class="px-2 py-1.5 font-normal">
            <Show
              when={activeOrganization.data}
              fallback={
                <Show
                  when={!props.hidePersonal}
                  fallback={organizationLocalization().organizations}
                >
                  <UserView />
                </Show>
              }
            >
              {(organization) => (
                <div class="flex items-center gap-2">
                  <BriefcaseBusiness class="size-4 text-muted-foreground" />
                  <OrganizationLabel
                    organization={organization()}
                    hideSlug={props.hideSlug}
                  />
                </div>
              )}
            </Show>
          </DropdownMenuLabel>
          <Show when={!props.hideSettings}>
            <DropdownMenuItem
              onSelect={() =>
                navigate({
                  to: "/settings/$path",
                  params: { path: "organizations" }
                })
              }
            >
              <Settings class="size-4 text-muted-foreground" />
              {organizationLocalization().manage}
            </DropdownMenuItem>
          </Show>
          <DropdownMenuSeparator />
          <Show when={activeOrganization.data && !props.hidePersonal}>
            <DropdownMenuItem onSelect={() => handleSetActive(null)}>
              <User class="size-4 text-muted-foreground" />
              Personal account
            </DropdownMenuItem>
          </Show>
          <Show when={selectableOrganizations().length > 0}>
            <For each={selectableOrganizations()}>
              {(organization) => (
                <DropdownMenuItem
                  onSelect={() => handleSetActive(organization)}
                >
                  <OrganizationLabel
                    organization={organization}
                    hideSlug={props.hideSlug}
                  />
                </DropdownMenuItem>
              )}
            </For>
          </Show>
          <Show when={!props.hideCreate}>
            <DropdownMenuSeparator />
            <DropdownMenuItem
              onSelect={() => {
                setIsOpen(false)
                setCreateOpen(true)
              }}
            >
              <PlusCircle class="size-4 text-muted-foreground" />
              {organizationLocalization().createOrganization}
            </DropdownMenuItem>
          </Show>
        </DropdownMenuContent>
      </DropdownMenu>
      <CreateOrganizationDialog
        open={createOpen()}
        onOpenChange={setCreateOpen}
      />
    </>
  )
}

export function OrganizationSwitcher(props: OrganizationSwitcherProps = {}) {
  const [isMounted, setIsMounted] = createSignal(false)

  onMount(() => setIsMounted(true))

  const content = createMemo(() =>
    isMounted() ? (
      <MountedOrganizationSwitcher {...props} />
    ) : (
      <OrganizationSwitcherTrigger {...props} />
    )
  )

  return <>{content()}</>
}

import { ensureSession as ensureSessionClient } from "@better-auth-ui/solid"
import { ensureSession as ensureSessionServer } from "@better-auth-ui/solid/server"
import { createFileRoute, notFound, redirect } from "@tanstack/solid-router"
import { createIsomorphicFn } from "@tanstack/solid-start"
import { getRequestHeaders } from "@tanstack/solid-start/server"
import { Organization } from "@/components/auth/organization/organization"
import { auth } from "@/lib/auth"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { authClient } from "@/lib/auth-client"

const validOrganizationPaths = Object.values(
  organizationPlugin().viewPaths.organization ?? {}
)

export const Route = createFileRoute("/organization/$slug/$path")({
  async beforeLoad({ params: { path }, context: { queryClient }, location }) {
    if (!validOrganizationPaths.includes(path)) {
      throw notFound()
    }

    const ensureSession = createIsomorphicFn()
      .server(() =>
        ensureSessionServer(queryClient, auth, { headers: getRequestHeaders() })
      )
      .client(() => ensureSessionClient(queryClient, authClient))

    const session = await ensureSession()

    if (!session) {
      throw redirect({
        to: "/auth/$path",
        params: { path: "sign-in" },
        search: { redirectTo: location.href }
      })
    }

    return { session }
  },
  component: OrganizationPage
})

function OrganizationPage() {
  const params = Route.useParams()

  return (
    <div class="mx-auto w-full max-w-3xl p-4 md:p-6">
      <Organization path={params().path} slug={params().slug} />
    </div>
  )
}

